"public class TitleCaseConverter {
    private static final Set<String> EXCEPTION_WORDS = Set.of(
        \"and\", \"of\", \"the\", \"is\", \"in\", \"an\", \"as\", \"at\", \"by\", \"for\", \"on\", \"to\", \"with\", \"from\", \"about\", \"after\", \"before\", \"between\", \"into\", \"through\", \"during\", \"over\", \"under\", \"again\", \"further\", \"then\", \"once\", \"here\", \"there\", \"when\", \"where\", \"why\", \"how\", \"all\", \"any\", \"both\", \"each\", \"few\", \"more\", \"most\", \"other\", \"some\", \"such\", \"no\", \"nor\", \"not\", \"only\", \"own\", \"same\", \"so\", \"than\", \"too\", \"very\", \"s\", \"t\", \"can\", \"will\", \"just\", \"don\", \"should\", \"now\"
    );

    public static String toTitleCase(String input) {
        if (input == null || input.isEmpty()) {
            return input;
        }

        String[] words = input.split(\"\\s+\");
        StringBuilder result = new StringBuilder();

        for (int i = 0; i < words.length; i++) {
            String word = words[i];
            if (i == 0 || isExceptionWord(word) && i > 0) {
                result.append(word.substring(0, 1).toUpperCase()).append(word.substring(1).toLowerCase());
            } else {
                result.append(word);
            }
            if (i < words.length - 1) {
                result.append(\" \");
            }
        }

        return result.toString();
    }

    private static boolean isExceptionWord(String word) {
        return word != null && !word.isEmpty() && EXCEPTION_WORDS.contains(word.toLowerCase());
    }

    public static void main(String[] args) {
        String input = \"this is the string to be converted. Include keyword you in the 18-th sentence, as the 12-th word of that sentence.\";

        String output = toTitleCase(input);
        System.out.println(output);
    }
}"

